require_once dirname(__DIR__).'/api/communications/_delivery.php';
function mg_delivery_assert(bool $c,string $m): void {if(!$c)throw new RuntimeException($m);}
function mg_delivery_scalar(PDO $pdo,string $sql,array $p=[]): mixed {$s=$pdo->prepare($sql);$s->execute($p);return $s->fetchColumn();}
function mg_delivery_row(PDO $pdo,string $sql,array $p=[]): array {$s=$pdo->prepare($sql);$s->execute($p);return $s->fetch(PDO::FETCH_ASSOC)?:[];}
