    $recipient=710001;$base=['recipient_user_id'=>$recipient,'channel'=>'email','template_key'=>'gift_ready','event_type'=>'microgift.ready','category'=>'transactional','payload'=>['subject'=>'Gift ready','private_token'=>'private-'.$runId,'safe'=>'visible'],'recipient_snapshot'=>['email'=>$runId.'@example.test'],'idempotency_key'=>'message:'.$runId.':primary'];
